public int minAddToMakeValid(String s) {
    int result = 0, balance = 0;
    for (char c : s.toCharArray()) {
        balance += (c == '(') ? 1 : -1;
        if (balance == -1) {
            result++;
            balance++;
        }
    }
    return result + balance;
}
```

